example.code:
import { BasePage } from './base';

export class CheckoutPage extends BasePage {
  readonly url = '/checkout';
  readonly payButton = this.page.getByRole('button', { name: 'Pay now' });
  readonly successBanner = this.page.getByText('Order confirmed');

  async pay(): Promise<void> {
    await this.payButton.click();
  }
}

import { test, expect } from '@playwright/test';
import { createUser } from '../fixtures/factory';
import { CheckoutPage } from '../pages/checkout';

test('checkout completes when gateway returns 200', async ({ page }) => {
  const user = createUser();
  await page.route('**/api/payments', route =>
    route.fulfill({ status: 200, body: JSON.stringify({ id: 'pi_x' }) })
  );
  const checkout = new CheckoutPage(page);
  await checkout.navigate();
  await checkout.pay();
  await expect(checkout.successBanner).toBeVisible();
});

await page.locator('.btn-primary').click();
await page.waitForTimeout(2000);
await expect(page).toHaveScreenshot('checkout.png');  // full-page — flakes on dynamic content
